/*
 *	GroundZonePOD
 */

GroundZonePOD::~GroundZonePOD() {
	finalize();
}

GroundZonePOD::GroundZonePOD(void) {
	_className = "GroundZone";
}


void GroundZonePOD::writeObject(ObjectOutputStream* stream) {
	int _currentOffset = stream->getOffset();
	stream->writeShort(0);
	int _varCount = GroundZonePOD::writeObjectMembers(stream);
	stream->writeShort(_currentOffset, _varCount);
}

int GroundZonePOD::writeObjectMembers(ObjectOutputStream* stream) {
	int _count = ZonePOD::writeObjectMembers(stream);

	uint32 _nameHashCode;
	int _offset;
	uint32 _totalSize;
	if (quadTree) {
	_nameHashCode = 0x7a5118bb; //GroundZone.quadTree
	TypeInfo<uint32>::toBinaryStream(&_nameHashCode, stream);
	_offset = stream->getOffset();
	stream->writeInt(0);
	TypeInfo<QuadTreeReference >::toBinaryStream(&quadTree.value(), stream);
	_totalSize = (uint32) (stream->getOffset() - (_offset + 4));
	stream->writeInt(_offset, _totalSize);
	_count++;
	}


	return _count;
}

bool GroundZonePOD::readObjectMember(ObjectInputStream* stream, const uint32& nameHashCode) {
	if (ZonePOD::readObjectMember(stream, nameHashCode))
		return true;

	switch(nameHashCode) {
	case 0x7a5118bb: //GroundZone.quadTree
		{
			QuadTreeReference _mnquadTree;
			TypeInfo<QuadTreeReference >::parseFromBinaryStream(&_mnquadTree, stream);
			quadTree = std::move(_mnquadTree);
		}
		return true;

	}

	return false;
}

void GroundZonePOD::readObject(ObjectInputStream* stream) {
	uint16 _varCount = stream->readShort();
	for (int i = 0; i < _varCount; ++i) {
		uint32 _nameHashCode;
		TypeInfo<uint32>::parseFromBinaryStream(&_nameHashCode, stream);

		uint32 _varSize = stream->readInt();

		int _currentOffset = stream->getOffset();

		if(GroundZonePOD::readObjectMember(stream, _nameHashCode)) {
		}

		stream->setOffset(_currentOffset + _varSize);
	}

}

void GroundZonePOD::writeObjectCompact(ObjectOutputStream* stream) {
	ZonePOD::writeObjectCompact(stream);

	TypeInfo<QuadTreeReference >::toBinaryStream(&quadTree.value(), stream);


}

